output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?father WHERE {
  wd:Q939956 wdt:P22 ?father
}

args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?father ?label WHERE {
  wd:Q939956 wdt:P22 ?father.
  ?father rdfs:label ?label.
  FILTER(LANG(?label) = "en")
}
